Normally overriding method must have the same parameter types and return type as base class method. But covariant method allows us to have a different return type for overriding method.

Covariant return type refers to return type of an overriding method. From Java 5 onwards, we can override a method by changing its return type only by abiding the condition that return type is a subclass of that of overridden method return type.

class Number{
    Number(int n)
    {
      this.n = n;
    }
    int n;
}
class SmallNumber extends Number{
   byte  n;
   SmallNumber(byte  n)
   {
       super(n);            
       this.n = n;
   }
}
class Covar {
    Number findSquare(int n)
   {
      int s = n*n;
      Number obj = new Number(s);
      return obj;
   }
}
class CovarSub extends Covar{
    SmallNumber findSquare(int n)
    {
        SmallNumber obj = new SmallNumber((byte)(n*n));
        return obj           ;
    }
    public static void main(String args[]){
      CovarSub cs1 = new CovarSub();
      SmallNumber sn = cs1.findSquare(10);
      System.out.println("Ouput is "+sn.n);
      }
}

import java.io.*;
public class filecopy {

   public static void main(String args[]) throws IOException {       
      String filename1 = args[0];
      String filename2 = args[1]; 
      FileInputStream in = null;
      FileOutputStream out = null;

      try {
         in = new FileInputStream(filename1);
         out = new FileOutputStream(filename2);
         int c;
         while ((c = in.read()) != -1) {
            out.write(c);
         }
      }finally {
         if (in != null) {
            in.close();
         }
         if (out != null) {
            out.close();
         }
      }
   }
}

