import java.util.Scanner;
class maginsquare{
    public static void main(String args[]){
        int n;
        System.out.println("n=");
        Scanner scanner = new Scanner(System.in);
        n = scanner.nextInt();
        int matrix[][] = new int[n][n];
        for(int i=0;i<n;i++){
            System.out.println("Enter the elements of row"+i);
            for(int j=0;j<n;j++)
            {
                matrix[i][j]=scanner.nextInt();
            }
        }
        if(isMagicSquare(matrix,n))
            System.out.println("It is a magic square");
        else
            System.out.println("It is not a magic square");
    }

    static boolean isMagicSquare(int mat[][],int n){
        int rowsum,prevrowsum=0;
        for(int i=0;i<n;i++){
            rowsum= 0;
            for(int j=0;j<n;j++)
                rowsum+=mat[i][j];
            if(prevrowsum==0)
                prevrowsum=rowsum;
            if( rowsum!=prevrowsum)
                return false;
        }
        int prevcolsum=0,colsum=0;
        for(int col=0;col<n;col++){
            colsum=0;
            for(int row=0;row<n;row++)
                colsum=colsum+mat[row][col];
            if(prevcolsum==0)
                prevcolsum=colsum;
            if(prevcolsum!=colsum)
                return false;
        }
        if(prevcolsum!=prevrowsum)
            return false;
        int diasum=0;
        for(int i=0;i<n;i++)
            diasum+=mat[i][i];
        if(diasum!=prevrowsum)
            return false;
        return true;
    }
}

