      static void deserialize(){
          A obj = null;
          try{
          FileInputStream instream = new FileInputStream("employee.ser");
          ObjectInputStream objStream = new ObjectInputStream(instream);
          obj = (A ) objStream.readObject();
          System.out.println("name is"+obj.getName());
          objStream.close();
          instream.close();
          }
          catch(IOException e){
               e.printStackTrace();
               return;
          }
          catch(ClassNotFoundException e){
              e.printStackTrace();
              return;
          }
      }
      public static void main(String args[]){
           A obj = new A("Mark",100);
             try {
               FileOutputStream fileOut =
                   new FileOutputStream("employee.ser");
               ObjectOutputStream out = new ObjectOutputStream(fileOut);
               out.writeObject(obj);
               out.close();
               fileOut.close();
               System.out.printf("Serialized data is saved in employee.ser");
      } catch (IOException i) {
         i.printStackTrace();
      }
      deserialize();
     }
}


ObjectOutputStream class has a writeObject() method which serializes the object.

ObjectInputStream has a readObject() method which deserializes the object

